import React from 'react';

const ContactoPage = () => {
  // Datos imágenes principales con las nuevas imágenes debajo
  const images = [
    {
      src: '/media/contactoPage/UCBA.png',
      alt: 'Entrada UCB',
      link: 'https://www.ucb.edu.bo/',
      subImages: [], // No tiene imagen secundaria
    },
    {
      src: '/media/contactoPage/SISE.png',
      alt: 'Logo SIS',
      link: 'https://www.ucb.edu.bo/contacto',
      subImages: [
        {
          src: '/media/contactoPage/SISE_sub1.png',
          alt: 'Sub imagen SIS 1',
          link: 'https://www.ucb.edu.bo/contacto/sub1',
        },
        {
          src: '/media/contactoPage/SISE_sub2.png',
          alt: 'Sub imagen SIS 2',
          link: 'https://www.ucb.edu.bo/contacto/sub2',
        },
      ],
    },
    {
      src: '/media/contactoPage/ADM - H.png',
      alt: 'Equipo ADM',
      link: 'https://www.ucb.edu.bo/nosotros',
      subImages: [
        {
          src: '/media/contactoPage/ADM_sub1.png',
          alt: 'Sub imagen ADM 1',
          link: 'https://www.ucb.edu.bo/nosotros/sub1',
        },
        {
          src: '/media/contactoPage/ADM_sub2.png',
          alt: 'Sub imagen ADM 2',
          link: 'https://www.ucb.edu.bo/nosotros/sub2',
        },
      ],
    },
  ];

  return (
    <main style={styles.page}>
      <div style={styles.container}>
        {/* Título */}
        <h1 style={styles.title}>UNIVERSIDAD CATÓLICA BOLIVIANA</h1>

        {/* Primera fila: imagen UCBA sola */}
        <div style={styles.imagesRow}>
          <a
            href={images[0].link}
            target="_blank"
            rel="noopener noreferrer"
            style={styles.link}
          >
            <img src={images[0].src} alt={images[0].alt} style={styles.mainImage} />
          </a>
        </div>

        {/* Segunda fila: Logos SIS y ADM con sus imágenes secundarias debajo */}
        <div style={styles.imagesRow}>
          {[images[1], images[2]].map(({ src, alt, link, subImages }, idx) => (
            <div key={idx} style={styles.imageColumn}>
              {/* Imagen principal */}
              <a href={link} target="_blank" rel="noopener noreferrer" style={styles.link}>
                <img src={src} alt={alt} style={styles.mainImage} />
              </a>

              {/* Sub imágenes debajo */}
              <div style={styles.subImagesRow}>
                {subImages.map(({ src: sSrc, alt: sAlt, link: sLink }, sIdx) => (
                  <a
                    key={sIdx}
                    href={sLink}
                    target="_blank"
                    rel="noopener noreferrer"
                    style={styles.subLink}
                  >
                    <img src={sSrc} alt={sAlt} style={styles.subImage} />
                  </a>
                ))}
              </div>
            </div>
          ))}
        </div>
      </div>
    </main>
  );
};

const styles = {
  page: {
    backgroundColor: '#F8F0E3',
    minHeight: '100vh',
    padding: '3rem 1rem',
    fontFamily: "'Segoe UI', Tahoma, Geneva, Verdana, sans-serif",
  },
  container: {
    maxWidth: '100%',
    color: '#052018',
    padding: '0 1rem',
  },
  title: {
    fontSize: '3rem',
    fontWeight: '900',
    marginBottom: '2rem',
    textAlign: 'center',
    color: '#052018',
  },
  imagesRow: {
    display: 'flex',
    justifyContent: 'center',
    gap: '1.5rem',
    flexWrap: 'wrap',
    marginBottom: '3rem',
  },
  link: {
    textDecoration: 'none',
    flex: '1 1 30%',
    maxWidth: 320,
  },
  mainImage: {
    width: '100%',
    maxHeight: 300,
    objectFit: 'cover',
    borderRadius: 16,
    boxShadow: '0 2px 12px rgba(0,0,0,0.15)',
    cursor: 'pointer',
    transition: 'transform 0.3s ease',
  },
  imageColumn: {
    display: 'flex',
    flexDirection: 'column',
    alignItems: 'center',
    gap: '1rem',
    flex: '1 1 30%',
    maxWidth: 320,
  },
  subImagesRow: {
    display: 'flex',
    gap: '1rem',
    justifyContent: 'center',
    flexWrap: 'wrap',
    width: '100%',
  },
  subLink: {
    flex: '1 1 48%',
    maxWidth: 140,
    textDecoration: 'none',
  },
  subImage: {
    width: '100%',
    maxHeight: 120,
    objectFit: 'cover',
    borderRadius: 12,
    boxShadow: '0 1px 8px rgba(0,0,0,0.1)',
    cursor: 'pointer',
    transition: 'transform 0.3s ease',
  },
};

export default ContactoPage;
